1328 bool VPlanTransforms::handleFindLastReductions(VPlan &Plan) {
1329   if (Plan.hasScalarVFOnly())
1330     return false;
1331 
1332   // We want to create the following nodes:
1333   // vector.body:
1334   //   ...new WidenPHI recipe introduced to keep the mask value for the latest
1335   //      iteration where any lane was active.
1336   //   mask.phi = phi [ ir<false>, vector.ph ], [ vp<new.mask>, vector.body ]
1337   //   ...data.phi (a VPReductionPHIRecipe for a FindLast reduction) already
1338   //      exists, but needs updating to use 'new.data' for the backedge value.
1339   //   data.phi = phi ir<default.val>, vp<new.data>
1340   //
1341   //   ...'data' and 'compare' created by existing nodes...
1342   //
1343   //   ...new recipes introduced to determine whether to update the reduction
1344   //      values or keep the current one.
1345   //   any.active = i1 any-of ir<compare>
1346   //   new.mask = select vp<any.active>, ir<compare>, vp<mask.phi>
1347   //   new.data = select vp<any.active>, ir<data>, ir<data.phi>
1348   //
1349   // middle.block:
1350   //   ...extract-last-active replaces compute-reduction-result.
1351   //   result = extract-last-active vp<new.data>, vp<new.mask>, ir<default.val>
1352 
1353   for (auto &Phi : Plan.getVectorLoopRegion()->getEntryBasicBlock()->phis()) {
1354     auto *PhiR = dyn_cast<VPReductionPHIRecipe>(&Phi);
1355     if (!PhiR || !RecurrenceDescriptor::isFindLastRecurrenceKind(
1356                      PhiR->getRecurrenceKind()))
1357       continue;
1358 
1359     // Find the condition for the select.
1360     auto *SelectR = cast<VPSingleDefRecipe>(&PhiR->getBackedgeRecipe());
1361     VPValue *Cond = nullptr, *Op1 = nullptr, *Op2 = nullptr;
1362     if (!match(SelectR,
1363                m_Select(m_VPValue(Cond), m_VPValue(Op1), m_VPValue(Op2))))
1364       return false;
1365 
1366     // Add mask phi.
1367     VPBuilder Builder = VPBuilder::getToInsertAfter(PhiR);
1368     auto *MaskPHI = new VPWidenPHIRecipe(nullptr, /*Start=*/Plan.getFalse());
1369     Builder.insert(MaskPHI);
1370 
1371     // Add select for mask.
1372     Builder.setInsertPoint(SelectR);
1373 
1374     if (Op1 == PhiR) {
1375       // Normalize to selecting the data operand when the condition is true by
1376       // swapping operands and negating the condition.
1377       std::swap(Op1, Op2);
1378       Cond = Builder.createNot(Cond);
1379     }
1380     assert(Op2 == PhiR && "data value must be selected if Cond is true");
1381 
1382     VPValue *AnyOf = Builder.createNaryOp(VPInstruction::AnyOf, {Cond});
1383     VPValue *MaskSelect = Builder.createSelect(AnyOf, Cond, MaskPHI);
1384     MaskPHI->addOperand(MaskSelect);
1385 
1386     // Replace select for data.
1387     VPValue *DataSelect =
1388         Builder.createSelect(AnyOf, Op1, Op2, SelectR->getDebugLoc());
1389     SelectR->replaceAllUsesWith(DataSelect);
1390     SelectR->eraseFromParent();
1391 
1392     // Find final reduction computation and replace it with an
1393     // extract.last.active intrinsic.
1394     auto *RdxResult =
1395         vputils::findUserOf<VPInstruction::ComputeReductionResult>(DataSelect);
1396     // TODO: Handle tail-folding.
1397     if (!RdxResult)
1398       return false;
1399     Builder.setInsertPoint(RdxResult);
1400     auto *ExtractLastActive =
1401         Builder.createNaryOp(VPInstruction::ExtractLastActive,
1402                              {DataSelect, MaskSelect, PhiR->getStartValue()},
1403                              RdxResult->getDebugLoc());
1404     RdxResult->replaceAllUsesWith(ExtractLastActive);
1405     RdxResult->eraseFromParent();
1406   }
1407 
1408   return true;
1409 }
