1411 bool VPlanTransforms::handleMultiUseReductions(VPlan &Plan) {
1412   for (auto &PhiR : make_early_inc_range(
1413            Plan.getVectorLoopRegion()->getEntryBasicBlock()->phis())) {
1414     auto *MinOrMaxPhiR = dyn_cast<VPReductionPHIRecipe>(&PhiR);
1415     // TODO: check for multi-uses in VPlan directly.
1416     if (!MinOrMaxPhiR || !MinOrMaxPhiR->hasUsesOutsideReductionChain())
1417       continue;
1418 
1419     // MinOrMaxPhiR has users outside the reduction cycle in the loop. Check if
1420     // the only other user is a FindLastIV reduction. MinOrMaxPhiR must have
1421     // exactly 2 users:
1422     // 1) the min/max operation of the reduction cycle, and
1423     // 2) the compare of a FindLastIV reduction cycle. This compare must match
1424     // the min/max operation - comparing MinOrMaxPhiR with the operand of the
1425     // min/max operation, and be used only by the select of the FindLastIV
1426     // reduction cycle.
1427     RecurKind RdxKind = MinOrMaxPhiR->getRecurrenceKind();
1428     assert(
1429         RecurrenceDescriptor::isIntMinMaxRecurrenceKind(RdxKind) &&
1430         "only min/max recurrences support users outside the reduction chain");
1431 
1432     auto *MinOrMaxOp =
1433         dyn_cast<VPRecipeWithIRFlags>(MinOrMaxPhiR->getBackedgeValue());
1434     if (!MinOrMaxOp)
1435       return false;
1436 
1437     // Check that MinOrMaxOp is a VPWidenIntrinsicRecipe or VPReplicateRecipe
1438     // with an intrinsic that matches the reduction kind.
1439     Intrinsic::ID ExpectedIntrinsicID = getMinMaxReductionIntrinsicOp(RdxKind);
1440     if (!match(MinOrMaxOp, m_Intrinsic(ExpectedIntrinsicID)))
1441       return false;
1442 
1443     // MinOrMaxOp must have 2 users: 1) MinOrMaxPhiR and 2)
1444     // ComputeReductionResult.
1445     assert(MinOrMaxOp->getNumUsers() == 2 &&
1446            "MinOrMaxOp must have exactly 2 users");
1447     VPValue *MinOrMaxOpValue = MinOrMaxOp->getOperand(0);
1448     if (MinOrMaxOpValue == MinOrMaxPhiR)
1449       MinOrMaxOpValue = MinOrMaxOp->getOperand(1);
1450 
1451     VPValue *CmpOpA;
1452     VPValue *CmpOpB;
1453     CmpPredicate Pred;
1454     auto *Cmp = dyn_cast_or_null<VPRecipeWithIRFlags>(vputils::findUserOf(
1455         MinOrMaxPhiR, m_Cmp(Pred, m_VPValue(CmpOpA), m_VPValue(CmpOpB))));
1456     if (!Cmp || Cmp->getNumUsers() != 1 ||
1457         (CmpOpA != MinOrMaxOpValue && CmpOpB != MinOrMaxOpValue))
1458       return false;
1459 
1460     if (MinOrMaxOpValue != CmpOpB)
1461       Pred = CmpInst::getSwappedPredicate(Pred);
1462 
1463     // MinOrMaxPhiR must have exactly 2 users:
1464     // * MinOrMaxOp,
1465     // * Cmp (that's part of a FindLastIV chain).
1466     if (MinOrMaxPhiR->getNumUsers() != 2)
1467       return false;
1468 
1469     VPInstruction *MinOrMaxResult =
1470         vputils::findUserOf<VPInstruction::ComputeReductionResult>(MinOrMaxOp);
1471     assert(is_contained(MinOrMaxPhiR->users(), MinOrMaxOp) &&
1472            "one user must be MinOrMaxOp");
1473     assert(MinOrMaxResult &&
1474            "MinOrMaxOp must have a ComputeReductionResult user");
1475 
1476     // Cmp must be used by the select of a FindLastIV chain.
1477     VPValue *Sel = dyn_cast<VPSingleDefRecipe>(Cmp->getSingleUser());
1478     VPValue *IVOp, *FindIV;
1479     if (!Sel || Sel->getNumUsers() != 2 ||
1480         !match(Sel,
1481                m_Select(m_Specific(Cmp), m_VPValue(IVOp), m_VPValue(FindIV))))
1482       return false;
1483 
1484     if (!isa<VPReductionPHIRecipe>(FindIV)) {
1485       std::swap(FindIV, IVOp);
1486       Pred = CmpInst::getInversePredicate(Pred);
1487     }
1488 
1489     auto *FindIVPhiR = dyn_cast<VPReductionPHIRecipe>(FindIV);
1490     if (!FindIVPhiR || !RecurrenceDescriptor::isFindIVRecurrenceKind(
1491                            FindIVPhiR->getRecurrenceKind()))
1492       return false;
1493 
1494     // Check if FindIVPhiR is a FindLast pattern by checking the MinMaxKind
1495     // on its ComputeReductionResult. SMax/UMax indicates FindLast.
1496     VPInstruction *FindIVResult =
1497         vputils::findUserOf<VPInstruction::ComputeReductionResult>(
1498             FindIVPhiR->getBackedgeValue());
1499     assert(FindIVResult &&
1500            "must be able to retrieve the FindIVResult VPInstruction");
1501     RecurKind FindIVMinMaxKind = FindIVResult->getRecurKind();
1502     if (FindIVMinMaxKind != RecurKind::SMax &&
1503         FindIVMinMaxKind != RecurKind::UMax)
1504       return false;
1505 
1506     // TODO: Support cases where IVOp is the IV increment.
1507     if (!match(IVOp, m_TruncOrSelf(m_VPValue(IVOp))) ||
1508         !isa<VPWidenIntOrFpInductionRecipe>(IVOp))
1509       return false;
1510 
1511     CmpInst::Predicate RdxPredicate = [RdxKind]() {
1512       switch (RdxKind) {
1513       case RecurKind::UMin:
1514         return CmpInst::ICMP_UGE;
1515       case RecurKind::UMax:
1516         return CmpInst::ICMP_ULE;
1517       case RecurKind::SMax:
1518         return CmpInst::ICMP_SLE;
1519       case RecurKind::SMin:
1520         return CmpInst::ICMP_SGE;
1521       default:
1522         llvm_unreachable("unhandled recurrence kind");
1523       }
1524     }();
1525 
1526     // TODO: Strict predicates need to find the first IV value for which the
1527     // predicate holds, not the last.
1528     if (Pred != RdxPredicate)
1529       return false;
1530 
1531     assert(!FindIVPhiR->isInLoop() && !FindIVPhiR->isOrdered() &&
1532            "cannot handle inloop/ordered reductions yet");
1533 
1534     // The reduction using MinOrMaxPhiR needs adjusting to compute the correct
1535     // result:
1536     //  1. We need to find the last IV for which the condition based on the
1537     //     min/max recurrence is true,
1538     //  2. Compare the partial min/max reduction result to its final value and,
1539     //  3. Select the lanes of the partial FindLastIV reductions which
1540     //     correspond to the lanes matching the min/max reduction result.
1541     //
1542     // For example, this transforms
1543     // vp<%min.result> = compute-reduction-result ir<%min.val.next>
1544     // vp<%iv.rdx> = compute-reduction-result (smax) vp<%min.idx.next>
1545     // vp<%cmp> = icmp ne vp<%iv.rdx>, SENTINEL
1546     // vp<%find.iv.result> = select vp<%cmp>, vp<%iv.rdx>, ir<0>
1547     //
1548     // into:
1549     //
1550     // vp<min.result> = compute-reduction-result ir<%min.val.next>
1551     // vp<%final.min.cmp> = icmp eq ir<%min.val.next>, vp<min.result>
1552     // vp<%final.iv> = select vp<%final.min.cmp>, vp<%min.idx.next>, SENTINEL
1553     // vp<%iv.rdx> = compute-reduction-result (smax) vp<%final.iv>
1554     // vp<%cmp> = icmp ne vp<%iv.rdx>, SENTINEL
1555     // vp<%find.iv.result> = select vp<%cmp>, vp<%iv.rdx>, ir<0>
1556     //
1557     // Find the FindIV result pattern.
1558     auto *FindIVSelect = findFindIVSelect(FindIVPhiR->getBackedgeValue());
1559     auto *FindIVCmp = FindIVSelect->getOperand(0)->getDefiningRecipe();
1560     auto *FindIVRdxResult = cast<VPInstruction>(FindIVCmp->getOperand(0));
1561     assert(FindIVSelect->getParent() == MinOrMaxResult->getParent() &&
1562            "both results must be computed in the same block");
1563     MinOrMaxResult->moveBefore(*FindIVRdxResult->getParent(),
1564                                FindIVRdxResult->getIterator());
1565 
1566     VPBuilder B(FindIVRdxResult);
1567     VPValue *MinOrMaxExiting = MinOrMaxResult->getOperand(0);
1568     auto *FinalMinOrMaxCmp =
1569         B.createICmp(CmpInst::ICMP_EQ, MinOrMaxExiting, MinOrMaxResult);
1570     VPValue *Sentinel = FindIVCmp->getOperand(1);
1571     VPValue *LastIVExiting = FindIVRdxResult->getOperand(0);
1572     auto *FinalIVSelect =
1573         B.createSelect(FinalMinOrMaxCmp, LastIVExiting, Sentinel);
1574     FindIVRdxResult->setOperand(0, FinalIVSelect);
1575   }
1576   return true;
1577 }
