2714 /// A common base class for interleaved memory operations.
2715 /// An Interleaved memory operation is a memory access method that combines
2716 /// multiple strided loads/stores into a single wide load/store with shuffles.
2717 /// The first operand is the start address. The optional operands are, in order,
2718 /// the stored values and the mask.
2719 class LLVM_ABI_FOR_TEST VPInterleaveBase : public VPRecipeBase,
2720                                            public VPIRMetadata {
2721   const InterleaveGroup<Instruction> *IG;
2722 
2723   /// Indicates if the interleave group is in a conditional block and requires a
2724   /// mask.
2725   bool HasMask = false;
2726 
2727   /// Indicates if gaps between members of the group need to be masked out or if
2728   /// unusued gaps can be loaded speculatively.
2729   bool NeedsMaskForGaps = false;
2730 
2731 protected:
2732   VPInterleaveBase(const unsigned char SC,
2733                    const InterleaveGroup<Instruction> *IG,
2734                    ArrayRef<VPValue *> Operands,
2735                    ArrayRef<VPValue *> StoredValues, VPValue *Mask,
2736                    bool NeedsMaskForGaps, const VPIRMetadata &MD, DebugLoc DL)
2737       : VPRecipeBase(SC, Operands, DL), VPIRMetadata(MD), IG(IG),
2738         NeedsMaskForGaps(NeedsMaskForGaps) {
2739     // TODO: extend the masked interleaved-group support to reversed access.
2740     assert((!Mask || !IG->isReverse()) &&
2741            "Reversed masked interleave-group not supported.");
2742     if (StoredValues.empty()) {
2743       for (unsigned I = 0; I < IG->getFactor(); ++I)
2744         if (Instruction *Inst = IG->getMember(I)) {
2745           assert(!Inst->getType()->isVoidTy() && "must have result");
2746           new VPRecipeValue(this, Inst);
2747         }
2748     } else {
2749       for (auto *SV : StoredValues)
2750         addOperand(SV);
2751     }
2752     if (Mask) {
2753       HasMask = true;
2754       addOperand(Mask);
2755     }
2756   }
2757 
2758 public:
2759   VPInterleaveBase *clone() override = 0;
2760 
2761   static inline bool classof(const VPRecipeBase *R) {
2762     return R->getVPRecipeID() == VPRecipeBase::VPInterleaveSC ||
2763            R->getVPRecipeID() == VPRecipeBase::VPInterleaveEVLSC;
2764   }
2765 
2766   static inline bool classof(const VPUser *U) {
2767     auto *R = dyn_cast<VPRecipeBase>(U);
2768     return R && classof(R);
2769   }
2770 
2771   /// Return the address accessed by this recipe.
2772   VPValue *getAddr() const {
2773     return getOperand(0); // Address is the 1st, mandatory operand.
2774   }
2775 
2776   /// Return the mask used by this recipe. Note that a full mask is represented
2777   /// by a nullptr.
2778   VPValue *getMask() const {
2779     // Mask is optional and the last operand.
2780     return HasMask ? getOperand(getNumOperands() - 1) : nullptr;
2781   }
2782 
2783   /// Return true if the access needs a mask because of the gaps.
2784   bool needsMaskForGaps() const { return NeedsMaskForGaps; }
2785 
2786   const InterleaveGroup<Instruction> *getInterleaveGroup() const { return IG; }
2787 
2788   Instruction *getInsertPos() const { return IG->getInsertPos(); }
2789 
2790   void execute(VPTransformState &State) override {
2791     llvm_unreachable("VPInterleaveBase should not be instantiated.");
2792   }
2793 
2794   /// Return the cost of this recipe.
2795   InstructionCost computeCost(ElementCount VF,
2796                               VPCostContext &Ctx) const override;
2797 
2798   /// Returns true if the recipe only uses the first lane of operand \p Op.
2799   bool usesFirstLaneOnly(const VPValue *Op) const override = 0;
2800 
2801   /// Returns the number of stored operands of this interleave group. Returns 0
2802   /// for load interleave groups.
2803   virtual unsigned getNumStoreOperands() const = 0;
2804 
2805   /// Return the VPValues stored by this interleave group. If it is a load
2806   /// interleave group, return an empty ArrayRef.
2807   ArrayRef<VPValue *> getStoredValues() const {
2808     return {op_end() - (getNumStoreOperands() + (HasMask ? 1 : 0)),
2809             getNumStoreOperands()};
2810   }
